'use client';

import React, { useState, useCallback } from 'react';
import { motion } from 'framer-motion';
import { ToolLayout } from '@/components/ui/ToolLayout';
import { DropZone } from '@/components/ui/DropZone';
import { FileList } from '@/components/ui/FileList';
import { Button } from '@/components/ui/Button';
import { CompareSlider } from '@/components/ui/CompareSlider';
import { ProgressBar } from '@/components/ui/ProgressBar';
import { useFileProcessing } from '@/hooks/useFileProcessing';
import { useCompressionHistory } from '@/hooks/useCompressionHistory';
import { useToast } from '@/hooks/useToast';
import { compressImage, createImagePreview } from '@/lib/image-processing';
import { downloadBlob, calculateCompressionRatio, formatBytes } from '@/lib/utils';
import { generateMetadata } from '@/config/seo';
import { Download, Settings, Sliders, ImageIcon } from 'lucide-react';

export const metadata = generateMetadata({
  title: 'Image Compressor - Compress Images Online Free',
    description: 'Compress JPG, PNG, WebP, and AVIF images directly in your browser. No upload required. Your files stay on your device.',
      path: '/image-compressor',
      });

      export default function ImageCompressorPage() {
        const [quality, setQuality] = useState(80);
          const [showCompare, setShowCompare] = useState(false);
            const { addToHistory } = useCompressionHistory();
              const { showSuccess, showError } = useToast();
                const {
                    files,
                        addFiles,
                            removeFile,
                                clearFiles,
                                    updateFile,
                                        processFiles,
                                            isProcessing,
                                              } = useFileProcessing({
                                                  maxFiles: 20,
                                                      maxSize: 50 * 1024 * 1024,
                                                          acceptedTypes: ['image/jpeg', 'image/png', 'image/webp', 'image/avif'],
                                                            });

                                                              const handleCompress = useCallback(async () => {
                                                                  const compress = async (fileWithMeta: typeof files[0]) => {
                                                                        const compressed = await compressImage(fileWithMeta.file, {
                                                                                quality,
                                                                                        maxWidth: 3840,
                                                                                                maxHeight: 2160,
                                                                                                        fileType: fileWithMeta.file.type,
                                                                                                              });

                                                                                                                    const preview = await createImagePreview(
                                                                                                                            new File([compressed], fileWithMeta.name)
                                                                                                                                  );

                                                                                                                                        return {
                                                                                                                                                ...fileWithMeta,
                                                                                                                                                        processedFile: compressed,
                                                                                                                                                                processedSize: compressed.size,
                                                                                                                                                                        preview,
                                                                                                                                                                                status: 'completed' as const,
                                                                                                                                                                                      };
                                                                                                                                                                                          };

                                                                                                                                                                                              try {
                                                                                                                                                                                                    await processFiles(compress);
                                                                                                                                                                                                          
                                                                                                                                                                                                                const totalOriginal = files.reduce((sum, f) => sum + f.size, 0);
                                                                                                                                                                                                                      const totalProcessed = files.reduce(
                                                                                                                                                                                                                              (sum, f) => sum + (f.processedSize || 0),
                                                                                                                                                                                                                                      0
                                                                                                                                                                                                                                            );
                                                                                                                                                                                                                                                  
                                                                                                                                                                                                                                                        addToHistory({
                                                                                                                                                                                                                                                                toolId: 'image-compressor',
                                                                                                                                                                                                                                                                        toolName: 'Image Compressor',
                                                                                                                                                                                                                                                                                filesProcessed: files.length,
                                                                                                                                                                                                                                                                                        spaceSaved: totalOriginal - totalProcessed,
                                                                                                                                                                                                                                                                                                timestamp: Date.now(),
                                                                                                                                                                                                                                                                                                      });
                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                  showSuccess(`Successfully compressed ${files.length} file(s)`);
                                                                                                                                                                                                                                                                                                                      } catch (error) {
                                                                                                                                                                                                                                                                                                                            showError('Failed to compress images');
                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                  }, [files, quality, processFiles, addToHistory, showSuccess, showError]);

                                                                                                                                                                                                                                                                                                                                    const handleDownloadAll = useCallback(() => {
                                                                                                                                                                                                                                                                                                                                        files
                                                                                                                                                                                                                                                                                                                                              .filter((f) => f.processedFile)
                                                                                                                                                                                                                                                                                                                                                    .forEach((f) => {
                                                                                                                                                                                                                                                                                                                                                            const ext = f.extension || 'jpg';
                                                                                                                                                                                                                                                                                                                                                                    downloadBlob(f.processedFile!, `compressed_${f.name}`);
                                                                                                                                                                                                                                                                                                                                                                          });
                                                                                                                                                                                                                                                                                                                                                                              showSuccess('All files downloaded');
                                                                                                                                                                                                                                                                                                                                                                                }, [files, showSuccess]);

                                                                                                                                                                                                                                                                                                                                                                                  return (
                                                                                                                                                                                                                                                                                                                                                                                      <ToolLayout
                                                                                                                                                                                                                                                                                                                                                                                            title="Image Compressor"
                                                                                                                                                                                                                                                                                                                                                                                                  description="Compress your images without compromising quality"
                                                                                                                                                                                                                                                                                                                                                                                                      >
                                                                                                                                                                                                                                                                                                                                                                                                            <div className="space-y-8">
                                                                                                                                                                                                                                                                                                                                                                                                                    {/* Quality Settings */}
                                                                                                                                                                                                                                                                                                                                                                                                                            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                                                                                                                                                                                                                                                                                                                                                                                                                                      <div className="col-span-2">
                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                Compression Quality: {quality}%
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </label>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <input
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            type="range"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            min="1"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            max="100"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            value={quality}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            onChange={(e) => setQuality(parseInt(e.target.value))}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer dark:bg-gray-700 accent-primary-500"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div className="flex justify-between text-xs text-gray-500 mt-1">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <span>Maximum Compression</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <span>Best Quality</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              {/* Preset Buttons */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div className="flex gap-2 mt-4">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {[
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        { label: 'Extreme', value: 20 },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        { label: 'High', value: 40 },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        { label: 'Medium', value: 60 },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        { label: 'Low', value: 80 },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        { label: 'Lossless', value: 100 },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      ].map((preset) => (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <Button
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        key={preset.value}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          variant={quality === preset.value ? 'primary' : 'ghost'}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            size="sm"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              onClick={() => setQuality(preset.value)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                {preset.label}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </Button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              ))}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div className="flex items-end justify-end gap-2">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <Button
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        onClick={handleCompress}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      disabled={files.length === 0 || isProcessing}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    loading={isProcessing}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  icon={<ImageIcon className="w-5 h-5" />}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            Compress All
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </Button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    {files.some((f) => f.processedFile) && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <Button
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  variant="secondary"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  onClick={handleDownloadAll}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  icon={<Download className="w-5 h-5" />}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                Download All
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </Button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    {/* Drop Zone */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <DropZone
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      onFilesSelected={addFiles}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                acceptedTypes={{ 'image/*': ['.jpg', '.jpeg', '.png', '.webp', '.avif'] }}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          maxFiles={20}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    maxSize={50 * 1024 * 1024}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            />

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    {/* File List */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <FileList
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      files={files}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                onRemove={removeFile}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          onClear={clearFiles}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  />

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          {/* Processing Progress */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  {isProcessing && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <ProgressBar
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        progress={
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      files.filter((f) => f.status === 'completed').length / files.length * 100
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              label="Processing images..."
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </ToolLayout>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }